#include<bits/stdc++.h>
using namespace std;

const int N = 400 + 5;

int n, dp[N][N];
string a;

int main() {
	cin >> a;
	a = "!" + a;
	n = a.size() - 1;
	memset(dp, 0x3f, sizeof dp);
	for(int i = 1; i <= n; i++)
	{
		dp[i][i] = 1;
	}
	for(int len = 2; len <= n; len++)
	{
		for(int l = 1; l <= n - len + 1; l++)
		{
			int r = l + len - 1;
			if(a[l] == a[r]) dp[l][r] = min(dp[l + 1][r], dp[l][r - 1]);
			for(int k = l; k < r; k++)
				dp[l][r] = min(dp[l][r], dp[l][k] + dp[k + 1][r]);
		}
	}
	cout << dp[1][n];
    return 0;
}
